-- Coach Toolkit V2 fresh database
create extension if not exists "uuid-ossp";
create table if not exists profiles(id uuid primary key default uuid_generate_v4(),user_id uuid not null unique references auth.users(id) on delete cascade,coach_name text,club text,age_group text,created_at timestamptz default now());
create table if not exists players(id uuid primary key default uuid_generate_v4(),user_id uuid not null references auth.users(id) on delete cascade,first_name text,last_name text,positions text[] default '{}',created_at timestamptz default now());
create table if not exists sessions(id uuid primary key default uuid_generate_v4(),user_id uuid not null references auth.users(id) on delete cascade,title text not null,session_date date,duration text,objective text,setup text,coach_points text,created_at timestamptz default now());
create table if not exists attendance(id uuid primary key default uuid_generate_v4(),user_id uuid not null references auth.users(id) on delete cascade,player_id uuid references players(id) on delete cascade,attendance_date date not null,present boolean default false,note text,created_at timestamptz default now());
create table if not exists player_ratings(id uuid primary key default uuid_generate_v4(),user_id uuid not null references auth.users(id) on delete cascade,player_id uuid references players(id) on delete cascade,rating_date date not null,context text,score int check(score>=1 and score<=10),note text,created_at timestamptz default now());
create table if not exists match_day_lineups(id uuid primary key default uuid_generate_v4(),user_id uuid not null references auth.users(id) on delete cascade,opponent text not null,match_date date,formation text not null,lineup jsonb not null default '{}'::jsonb,bench jsonb not null default '[]'::jsonb,notes text,created_at timestamptz default now());
create table if not exists match_reports(id uuid primary key default uuid_generate_v4(),user_id uuid not null references auth.users(id) on delete cascade,opponent text not null,match_date date,score text,positives text,improvements text,summary text,created_at timestamptz default now());
alter table profiles enable row level security;alter table players enable row level security;alter table sessions enable row level security;alter table attendance enable row level security;alter table player_ratings enable row level security;alter table match_day_lineups enable row level security;alter table match_reports enable row level security;
drop policy if exists "profiles select own" on profiles;drop policy if exists "profiles insert own" on profiles;drop policy if exists "profiles update own" on profiles;drop policy if exists "profiles delete own" on profiles;create policy "profiles select own" on profiles for select using(auth.uid()=user_id);create policy "profiles insert own" on profiles for insert with check(auth.uid()=user_id);create policy "profiles update own" on profiles for update using(auth.uid()=user_id);create policy "profiles delete own" on profiles for delete using(auth.uid()=user_id);
