drop policy if exists "attendance select own" on attendance;drop policy if exists "attendance insert own" on attendance;drop policy if exists "attendance update own" on attendance;drop policy if exists "attendance delete own" on attendance;create policy "attendance select own" on attendance for select using(auth.uid()=user_id);create policy "attendance insert own" on attendance for insert with check(auth.uid()=user_id);create policy "attendance update own" on attendance for update using(auth.uid()=user_id);create policy "attendance delete own" on attendance for delete using(auth.uid()=user_id);
drop policy if exists "ratings select own" on player_ratings;drop policy if exists "ratings insert own" on player_ratings;drop policy if exists "ratings update own" on player_ratings;drop policy if exists "ratings delete own" on player_ratings;create policy "ratings select own" on player_ratings for select using(auth.uid()=user_id);create policy "ratings insert own" on player_ratings for insert with check(auth.uid()=user_id);create policy "ratings update own" on player_ratings for update using(auth.uid()=user_id);create policy "ratings delete own" on player_ratings for delete using(auth.uid()=user_id);
drop policy if exists "lineups select own" on match_day_lineups;drop policy if exists "lineups insert own" on match_day_lineups;drop policy if exists "lineups update own" on match_day_lineups;drop policy if exists "lineups delete own" on match_day_lineups;create policy "lineups select own" on match_day_lineups for select using(auth.uid()=user_id);create policy "lineups insert own" on match_day_lineups for insert with check(auth.uid()=user_id);create policy "lineups update own" on match_day_lineups for update using(auth.uid()=user_id);create policy "lineups delete own" on match_day_lineups for delete using(auth.uid()=user_id);
drop policy if exists "match reports select own" on match_reports;drop policy if exists "match reports insert own" on match_reports;drop policy if exists "match reports update own" on match_reports;drop policy if exists "match reports delete own" on match_reports;create policy "match reports select own" on match_reports for select using(auth.uid()=user_id);create policy "match reports insert own" on match_reports for insert with check(auth.uid()=user_id);create policy "match reports update own" on match_reports for update using(auth.uid()=user_id);create policy "match reports delete own" on match_reports for delete using(auth.uid()=user_id);
